  function clamp(v) { return Math.max(0, Math.min(1, v)); }
  function easeOut(v) { v = clamp(v); return 1 - Math.pow(1 - v, 3); }
  function easeInOut(v) { v = clamp(v); return v < 0.5 ? 4*v*v*v : 1 - Math.pow(-2*v+2,3)/2; }
  function easeElastic(v) { v = clamp(v); return v === 0 || v === 1 ? v : Math.pow(2,-10*v)*Math.sin((v*10-0.75)*((2*Math.PI)/3))+1; }
  function lerp(a,b,t) { return a + (b-a)*t; }
  function roundedRect(ctx,x,y,w,h,r) {
    ctx.beginPath();
    ctx.moveTo(x+r,y); ctx.lineTo(x+w-r,y);
    ctx.quadraticCurveTo(x+w,y,x+w,y+r);
    ctx.lineTo(x+w,y+h-r);
    ctx.quadraticCurveTo(x+w,y+h,x+w-r,y+h);
    ctx.lineTo(x+r,y+h);
    ctx.quadraticCurveTo(x,y+h,x,y+h-r);
    ctx.lineTo(x,y+r);
    ctx.quadraticCurveTo(x,y,x+r,y);
    ctx.closePath();
  }
  function drawBg(ctx,w,h,t) {
    const g = ctx.createLinearGradient(0,0,w,h);
    g.addColorStop(0,'#030712');
    g.addColorStop(0.5,'#07172A');
    g.addColorStop(1,'#15102A');
    ctx.fillStyle = g; ctx.fillRect(0,0,w,h);
    ctx.save(); ctx.globalCompositeOperation='screen'; ctx.globalAlpha=0.18;
    const c1=ctx.createRadialGradient(w*0.2,h*0.15,10,w*0.2,h*0.15,500);
    c1.addColorStop(0,'#00D4FF'); c1.addColorStop(1,'rgba(0,212,255,0)');
    ctx.fillStyle=c1; ctx.fillRect(0,0,w,h);
    const c2=ctx.createRadialGradient(w*0.85,h*0.75,10,w*0.85,h*0.75,550);
    c2.addColorStop(0,'#B487FF'); c2.addColorStop(1,'rgba(180,135,255,0)');
    ctx.fillStyle=c2; ctx.fillRect(0,0,w,h);
    ctx.restore();
  }
  function drawGrid(ctx,w,h,t,alpha) {
    ctx.save(); ctx.globalAlpha=0.07*alpha; ctx.strokeStyle='#DFF6FF';
    for(let x=-200;x<w+200;x+=80){ ctx.beginPath(); ctx.moveTo(x+(t*14)%80,h*0.1); ctx.lineTo(x-300+(t*14)%80,h); ctx.stroke(); }
    ctx.restore();
  }

function createRenderer() {
  const cols=40, chars='01アイウエオカキクケコ0123456789ABCDEF<>{}[]';
  const colData=Array.from({length:cols},(_,i)=>({
    x:i, speed:120+Math.random()*200, offset:Math.random()*5000,
    chars:Array.from({length:30},()=>chars[Math.floor(Math.random()*chars.length)])
  }));
  function render(t,ctx2) {
    const ctx=ctx2.mainContext,w=ctx2.width,h=ctx2.height;
    ctx.fillStyle='rgba(3,7,18,0.15)'; ctx.fillRect(0,0,w,h);
    if(t<0.05){ drawBg(ctx,w,h,t); }
    const colW=w/cols;
    for(const col of colData){
      const x=col.x*colW+colW/2;
      const head=(t*col.speed+col.offset)%(h+400)-200;
      ctx.font='700 18px monospace';
      for(let i=0;i<col.chars.length;i++){
        const y=head-i*22;
        if(y<-30||y>h+30) continue;
        const fade=i===0?1:Math.max(0,1-i*0.06);
        ctx.globalAlpha=fade*0.85;
        ctx.fillStyle=i===0?'#F8FBFF':(i<3?'#7BD88F':'#00D4FF');
        ctx.fillText(col.chars[(i+Math.floor(t*8))%col.chars.length],x,y);
      }
    }
    ctx.globalAlpha=1;
    ctx.save(); ctx.globalAlpha=easeOut((t-2)/1);
    roundedRect(ctx,w/2-280,h*0.38,560,120,24);
    ctx.fillStyle='rgba(5,12,24,0.85)'; ctx.fill();
    ctx.strokeStyle='#7BD88F88'; ctx.lineWidth=2; ctx.stroke();
    ctx.textAlign='center'; ctx.font='900 48px Arial,sans-serif'; ctx.fillStyle='#F8FBFF';
    ctx.fillText('Code Matrix',w/2,h*0.46);
    ctx.font='600 20px Arial,sans-serif'; ctx.fillStyle='#9CB7CC';
    ctx.fillText('Digital rain effect',w/2,h*0.52);
    ctx.restore();
  }
  return {render};
}
